Create the `packages/skills/` directory and its configuration files to establish the `@dorkos/skills` package in the monorepo.

## Steps

1. Create `packages/skills/` directory.

2. Create `packages/skills/package.json` with this exact content:

```json
{
  "name": "@dorkos/skills",
  "version": "0.0.0",
  "private": true,
  "type": "module",
  "scripts": {
    "build": "tsc",
    "typecheck": "tsc --noEmit",
    "test": "vitest",
    "lint": "eslint src/"
  },
  "exports": {
    "./schema": {
      "types": "./src/schema.ts",
      "default": "./dist/schema.js"
    },
    "./task-schema": {
      "types": "./src/task-schema.ts",
      "default": "./dist/task-schema.js"
    },
    "./command-schema": {
      "types": "./src/command-schema.ts",
      "default": "./dist/command-schema.js"
    },
    "./types": {
      "types": "./src/types.ts",
      "default": "./dist/types.js"
    },
    "./constants": {
      "types": "./src/constants.ts",
      "default": "./dist/constants.js"
    },
    "./slug": {
      "types": "./src/slug.ts",
      "default": "./dist/slug.js"
    },
    "./duration": {
      "types": "./src/duration.ts",
      "default": "./dist/duration.js"
    },
    "./parser": {
      "types": "./src/parser.ts",
      "default": "./dist/parser.js"
    },
    "./writer": {
      "types": "./src/writer.ts",
      "default": "./dist/writer.js"
    },
    "./scanner": {
      "types": "./src/scanner.ts",
      "default": "./dist/scanner.js"
    },
    "./validator": {
      "types": "./src/validator.ts",
      "default": "./dist/validator.js"
    }
  },
  "dependencies": {
    "gray-matter": "^4.0.3",
    "zod": "^3.24.0"
  },
  "devDependencies": {
    "@dorkos/eslint-config": "workspace:*",
    "@dorkos/typescript-config": "workspace:*",
    "vitest": "^3.1.1"
  }
}
```

3. Create `packages/skills/tsconfig.json`:

```json
{
  "extends": "@dorkos/typescript-config/node.json",
  "compilerOptions": {
    "outDir": "./dist"
  },
  "include": ["src/**/*"],
  "exclude": ["src/__tests__/**"]
}
```

4. Create `packages/skills/src/` directory.

5. Wire the package into `turbo.json` — ensure the `build`, `typecheck`, `test`, and `lint` tasks include `@dorkos/skills`. Since turbo uses pipeline/tasks definitions that match script names, verify the existing turbo.json task definitions cover `@dorkos/skills` automatically (they typically do for all workspace packages). If any package-specific turbo configuration is needed, add it.

6. Run `pnpm install` from the repo root to link the new workspace package.

7. Verify the package is recognized: `pnpm --filter @dorkos/skills typecheck` should run (it will fail since there are no source files yet — that's fine, just verify the package is found).

## Acceptance Criteria

- `packages/skills/package.json` exists with the exact exports map, dependencies, and scripts listed above.
- `packages/skills/tsconfig.json` extends `@dorkos/typescript-config/node.json`.
- `pnpm install` succeeds without errors.
- The package is visible in the Turborepo dependency graph.

Implement the base SKILL.md frontmatter schema in `packages/skills/src/schema.ts` conforming to the agentskills.io specification, plus comprehensive tests.

## Implementation: `packages/skills/src/schema.ts`

```typescript
import { z } from 'zod';

/**
 * SKILL.md name field validation.
 *
 * Per the agentskills.io spec:
 * - 1-64 characters
 * - Lowercase alphanumeric and hyphens only
 * - Must not start or end with a hyphen
 * - Must not contain consecutive hyphens
 * - Must match the parent directory name (enforced at parse time, not in schema)
 */
export const SkillNameSchema = z
  .string()
  .min(1)
  .max(64)
  .regex(
    /^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/,
    'Must be lowercase alphanumeric with hyphens, not starting/ending with hyphen'
  )
  .refine((s) => !s.includes('--'), 'Must not contain consecutive hyphens');

/**
 * Base SKILL.md frontmatter schema.
 *
 * Conforms to the agentskills.io open standard. All DorkOS-specific
 * schemas (tasks, commands) extend this base.
 *
 * @see https://agentskills.io/specification#skill-md-format
 */
export const SkillFrontmatterSchema = z.object({
  /** Kebab-case identifier. Must match the parent directory name. */
  name: SkillNameSchema,

  /** What the skill does and when to use it. 1-1024 characters. */
  description: z.string().min(1).max(1024),

  /** License name or reference to a bundled license file. */
  license: z.string().optional(),

  /** Environment requirements (intended product, system packages, network access). */
  compatibility: z.string().max(500).optional(),

  /** Arbitrary key-value metadata for client-specific extensions. */
  metadata: z.record(z.string(), z.string()).optional(),

  /** Space-delimited list of pre-approved tools. */
  'allowed-tools': z.string().optional(),
});

export type SkillFrontmatter = z.infer<typeof SkillFrontmatterSchema>;
```

## Tests: `packages/skills/src/__tests__/schema.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { SkillFrontmatterSchema, SkillNameSchema } from '../schema.js';

describe('SkillNameSchema', () => {
  it('accepts a valid kebab-case name', () => {
    expect(SkillNameSchema.safeParse('daily-health-check').success).toBe(true);
  });

  it('accepts a single character', () => {
    expect(SkillNameSchema.safeParse('a').success).toBe(true);
  });

  it('accepts a single digit', () => {
    expect(SkillNameSchema.safeParse('1').success).toBe(true);
  });

  it('rejects empty string', () => {
    expect(SkillNameSchema.safeParse('').success).toBe(false);
  });

  it('rejects name longer than 64 characters', () => {
    expect(SkillNameSchema.safeParse('a'.repeat(65)).success).toBe(false);
  });

  it('rejects uppercase characters', () => {
    expect(SkillNameSchema.safeParse('Daily-Check').success).toBe(false);
  });

  it('rejects name starting with hyphen', () => {
    expect(SkillNameSchema.safeParse('-daily-check').success).toBe(false);
  });

  it('rejects name ending with hyphen', () => {
    expect(SkillNameSchema.safeParse('daily-check-').success).toBe(false);
  });

  it('rejects consecutive hyphens', () => {
    expect(SkillNameSchema.safeParse('daily--check').success).toBe(false);
  });

  it('rejects special characters', () => {
    expect(SkillNameSchema.safeParse('daily_check').success).toBe(false);
    expect(SkillNameSchema.safeParse('daily.check').success).toBe(false);
    expect(SkillNameSchema.safeParse('daily check').success).toBe(false);
  });
});

describe('SkillFrontmatterSchema', () => {
  const minimal = { name: 'my-skill', description: 'Does something useful' };

  it('accepts minimal valid frontmatter (name + description)', () => {
    const result = SkillFrontmatterSchema.safeParse(minimal);
    expect(result.success).toBe(true);
  });

  it('accepts all optional fields', () => {
    const full = {
      ...minimal,
      license: 'MIT',
      compatibility: 'Requires Node.js 20+',
      metadata: { category: 'devops', author: 'kai' },
      'allowed-tools': 'Read Edit Bash',
    };
    const result = SkillFrontmatterSchema.safeParse(full);
    expect(result.success).toBe(true);
  });

  it('rejects missing name', () => {
    const result = SkillFrontmatterSchema.safeParse({ description: 'test' });
    expect(result.success).toBe(false);
  });

  it('rejects missing description', () => {
    const result = SkillFrontmatterSchema.safeParse({ name: 'test' });
    expect(result.success).toBe(false);
  });

  it('rejects name with uppercase', () => {
    const result = SkillFrontmatterSchema.safeParse({ name: 'My-Skill', description: 'test' });
    expect(result.success).toBe(false);
  });

  it('rejects description longer than 1024 characters', () => {
    const result = SkillFrontmatterSchema.safeParse({
      name: 'test',
      description: 'a'.repeat(1025),
    });
    expect(result.success).toBe(false);
  });

  it('accepts valid metadata map', () => {
    const result = SkillFrontmatterSchema.safeParse({
      ...minimal,
      metadata: { key: 'value', another: 'entry' },
    });
    expect(result.success).toBe(true);
  });

  it('rejects non-string metadata values', () => {
    const result = SkillFrontmatterSchema.safeParse({
      ...minimal,
      metadata: { key: 123 },
    });
    expect(result.success).toBe(false);
  });
});
```

## Acceptance Criteria

- `SkillNameSchema` validates all agentskills.io naming rules (1-64 chars, lowercase alphanumeric + hyphens, no leading/trailing/consecutive hyphens).
- `SkillFrontmatterSchema` requires `name` and `description`, accepts all optional fields (`license`, `compatibility`, `metadata`, `allowed-tools`).
- `SkillFrontmatter` type is exported.
- All 11+ test cases pass in `schema.test.ts`.
- `pnpm vitest run packages/skills/src/__tests__/schema.test.ts` succeeds.

Implement three browser-safe utility modules: `constants.ts`, `types.ts`, and `slug.ts`, plus tests for slug utilities.

## Implementation: `packages/skills/src/constants.ts`

```typescript
/** Required filename inside every skill directory. */
export const SKILL_FILENAME = 'SKILL.md' as const;

/** Standard subdirectory names per the agentskills.io spec. */
export const SKILL_SUBDIRS = ['scripts', 'references', 'assets'] as const;

/**
 * Build the path to a SKILL.md file inside a parent directory.
 *
 * @param parentDir - The directory containing skill subdirectories
 * @param name - The skill's kebab-case name (directory name)
 * @returns Absolute path like `{parentDir}/{name}/SKILL.md`
 */
export function skillFilePath(parentDir: string, name: string): string {
  return `${parentDir}/${name}/${SKILL_FILENAME}`;
}

/**
 * Build the path to a skill's directory.
 *
 * @param parentDir - The directory containing skill subdirectories
 * @param name - The skill's kebab-case name
 * @returns Absolute path like `{parentDir}/{name}/`
 */
export function skillDirPath(parentDir: string, name: string): string {
  return `${parentDir}/${name}`;
}
```

## Implementation: `packages/skills/src/types.ts`

```typescript
import type { SkillFrontmatter } from './schema.js';
import type { TaskFrontmatter } from './task-schema.js';
import type { CommandFrontmatter } from './command-schema.js';

/** Discriminated parse result. */
export type ParseResult<T> =
  | { ok: true; definition: T }
  | { ok: false; error: string; filePath: string };

/** Base parsed skill definition. */
export interface SkillDefinition {
  /** Kebab-case identifier (matches directory name). */
  name: string;
  /** Validated frontmatter. */
  meta: SkillFrontmatter;
  /** Markdown body — the agent instructions. */
  body: string;
  /** Absolute path to the SKILL.md file. */
  filePath: string;
  /** Absolute path to the skill directory (parent of SKILL.md). */
  dirPath: string;
}

/** Parsed task definition with location-derived context. */
export interface TaskDefinition extends Omit<SkillDefinition, 'meta'> {
  meta: TaskFrontmatter;
  /** Whether the task comes from a project or global tasks directory. */
  scope: 'project' | 'global';
  /** Absolute path to the project root (present for project-scoped tasks). */
  projectPath?: string;
}

/** Parsed command definition with invocation metadata. */
export interface CommandDefinition extends Omit<SkillDefinition, 'meta'> {
  meta: CommandFrontmatter;
  /** Namespace prefix (from subdirectory name, if any). */
  namespace?: string;
  /** Full invocation string (e.g., "/frontend:deploy" or "/commit"). */
  fullCommand: string;
}
```

Note: `types.ts` imports from `task-schema.ts` and `command-schema.ts`, so those must exist first (or be stubbed). Since tasks 1.2, 1.3, and 1.4 can run in parallel, create minimal stubs if needed, or implement types.ts after the schemas are in place.

## Implementation: `packages/skills/src/slug.ts`

```typescript
/**
 * Validate a string against SKILL.md naming rules.
 *
 * Rules: 1-64 chars, lowercase alphanumeric + hyphens, no leading/trailing
 * hyphens, no consecutive hyphens.
 *
 * @param s - The string to validate
 * @returns True if valid as a SKILL.md name
 */
export function validateSlug(s: string): boolean {
  if (s.length < 1 || s.length > 64) return false;
  if (s.includes('--')) return false;
  return /^[a-z0-9]([a-z0-9-]*[a-z0-9])?$/.test(s);
}

/**
 * Convert a display name to a valid SKILL.md slug.
 *
 * @param displayName - Human-readable name (e.g., "Daily Health Check")
 * @returns Kebab-case slug (e.g., "daily-health-check")
 */
export function slugify(displayName: string): string {
  return displayName
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .replace(/-{2,}/g, '-')
    .slice(0, 64);
}

/**
 * Convert a kebab-case slug to a human-readable title.
 *
 * @param slug - Kebab-case identifier (e.g., "daily-health-check")
 * @returns Title-cased string (e.g., "Daily Health Check")
 */
export function humanize(slug: string): string {
  return slug
    .split('-')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}
```

## Tests: `packages/skills/src/__tests__/slug.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { validateSlug, slugify, humanize } from '../slug.js';

describe('validateSlug', () => {
  it('accepts valid kebab-case slugs', () => {
    expect(validateSlug('daily-health-check')).toBe(true);
    expect(validateSlug('a')).toBe(true);
    expect(validateSlug('a1b2')).toBe(true);
    expect(validateSlug('my-skill')).toBe(true);
  });

  it('rejects empty string', () => {
    expect(validateSlug('')).toBe(false);
  });

  it('rejects strings longer than 64 chars', () => {
    expect(validateSlug('a'.repeat(65))).toBe(false);
  });

  it('rejects uppercase', () => {
    expect(validateSlug('Daily')).toBe(false);
  });

  it('rejects leading hyphen', () => {
    expect(validateSlug('-daily')).toBe(false);
  });

  it('rejects trailing hyphen', () => {
    expect(validateSlug('daily-')).toBe(false);
  });

  it('rejects consecutive hyphens', () => {
    expect(validateSlug('daily--check')).toBe(false);
  });

  it('rejects special characters', () => {
    expect(validateSlug('daily_check')).toBe(false);
    expect(validateSlug('daily.check')).toBe(false);
    expect(validateSlug('daily check')).toBe(false);
  });
});

describe('slugify', () => {
  it('converts a display name to kebab-case', () => {
    expect(slugify('Daily Health Check')).toBe('daily-health-check');
  });

  it('strips special characters', () => {
    expect(slugify('Hello, World!')).toBe('hello-world');
  });

  it('handles leading/trailing whitespace', () => {
    expect(slugify('  My Skill  ')).toBe('my-skill');
  });

  it('truncates to 64 characters', () => {
    const long = 'a '.repeat(40);
    expect(slugify(long).length).toBeLessThanOrEqual(64);
  });

  it('cleans up leading/trailing hyphens from substitution', () => {
    expect(slugify('---hello---')).toBe('hello');
  });

  it('collapses consecutive hyphens', () => {
    expect(slugify('hello   world')).toBe('hello-world');
  });

  it('produces a valid slug', () => {
    const result = slugify('My Cool Skill #1');
    expect(validateSlug(result)).toBe(true);
  });
});

describe('humanize', () => {
  it('converts kebab-case to title case', () => {
    expect(humanize('daily-health-check')).toBe('Daily Health Check');
  });

  it('handles single word', () => {
    expect(humanize('deploy')).toBe('Deploy');
  });

  it('handles multiple hyphens', () => {
    expect(humanize('run-all-tests-now')).toBe('Run All Tests Now');
  });

  it('round-trips with slugify (approximately)', () => {
    const original = 'Daily Health Check';
    const slug = slugify(original);
    expect(humanize(slug)).toBe(original);
  });
});
```

## Acceptance Criteria

- `SKILL_FILENAME` is `'SKILL.md'`, `SKILL_SUBDIRS` is `['scripts', 'references', 'assets']`.
- `skillFilePath('/tasks', 'my-task')` returns `'/tasks/my-task/SKILL.md'`.
- `skillDirPath('/tasks', 'my-task')` returns `'/tasks/my-task'`.
- All type interfaces (`SkillDefinition`, `TaskDefinition`, `CommandDefinition`, `ParseResult`) are exported.
- `validateSlug` correctly validates all naming rules.
- `slugify` produces valid slugs from display names.
- `humanize` converts slugs back to title case.
- All slug tests pass.

Implement the duration parsing and formatting utilities in `packages/skills/src/duration.ts`, plus comprehensive tests.

## Implementation: `packages/skills/src/duration.ts`

```typescript
import { z } from 'zod';

/** Duration string pattern: "5m", "1h", "30s", "2h30m", "1h15m30s". */
export const DurationSchema = z
  .string()
  .regex(/^(\d+h)?(\d+m)?(\d+s)?$/, 'Duration must be like "5m", "1h", "30s", or "2h30m"')
  .refine((v) => v.length > 0, 'Duration must not be empty');

/**
 * Parse a duration string to milliseconds.
 *
 * @param duration - Duration string matching DurationSchema (e.g., "2h30m")
 * @returns Duration in milliseconds
 */
export function parseDuration(duration: string): number {
  let ms = 0;
  const hours = duration.match(/(\d+)h/);
  const minutes = duration.match(/(\d+)m/);
  const seconds = duration.match(/(\d+)s/);
  if (hours) ms += parseInt(hours[1], 10) * 3_600_000;
  if (minutes) ms += parseInt(minutes[1], 10) * 60_000;
  if (seconds) ms += parseInt(seconds[1], 10) * 1_000;
  return ms;
}

/**
 * Format milliseconds as a human-readable duration string.
 *
 * @param ms - Duration in milliseconds
 * @returns Duration string (e.g., "2h30m")
 */
export function formatDuration(ms: number): string {
  const hours = Math.floor(ms / 3_600_000);
  const minutes = Math.floor((ms % 3_600_000) / 60_000);
  const seconds = Math.floor((ms % 60_000) / 1_000);

  const parts: string[] = [];
  if (hours > 0) parts.push(`${hours}h`);
  if (minutes > 0) parts.push(`${minutes}m`);
  if (seconds > 0) parts.push(`${seconds}s`);
  return parts.join('') || '0s';
}
```

## Tests: `packages/skills/src/__tests__/duration.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { DurationSchema, parseDuration, formatDuration } from '../duration.js';

describe('DurationSchema', () => {
  it('accepts valid duration strings', () => {
    expect(DurationSchema.safeParse('5m').success).toBe(true);
    expect(DurationSchema.safeParse('1h').success).toBe(true);
    expect(DurationSchema.safeParse('30s').success).toBe(true);
    expect(DurationSchema.safeParse('2h30m').success).toBe(true);
    expect(DurationSchema.safeParse('1h15m30s').success).toBe(true);
  });

  it('rejects empty string', () => {
    expect(DurationSchema.safeParse('').success).toBe(false);
  });

  it('rejects invalid duration strings', () => {
    expect(DurationSchema.safeParse('abc').success).toBe(false);
    expect(DurationSchema.safeParse('5').success).toBe(false);
    expect(DurationSchema.safeParse('5x').success).toBe(false);
    expect(DurationSchema.safeParse('five minutes').success).toBe(false);
  });
});

describe('parseDuration', () => {
  it('parses minutes only', () => {
    expect(parseDuration('5m')).toBe(300_000);
  });

  it('parses hours only', () => {
    expect(parseDuration('2h')).toBe(7_200_000);
  });

  it('parses seconds only', () => {
    expect(parseDuration('30s')).toBe(30_000);
  });

  it('parses combined duration', () => {
    expect(parseDuration('2h30m')).toBe(9_000_000);
  });

  it('parses full hours+minutes+seconds', () => {
    expect(parseDuration('1h15m30s')).toBe(4_530_000);
  });

  it('returns 0 for empty-ish input', () => {
    expect(parseDuration('')).toBe(0);
  });
});

describe('formatDuration', () => {
  it('formats hours and minutes', () => {
    expect(formatDuration(9_000_000)).toBe('2h30m');
  });

  it('formats zero as 0s', () => {
    expect(formatDuration(0)).toBe('0s');
  });

  it('formats seconds only', () => {
    expect(formatDuration(45_000)).toBe('45s');
  });

  it('formats large values', () => {
    expect(formatDuration(86_400_000)).toBe('24h');
  });

  it('round-trips with parseDuration', () => {
    expect(formatDuration(parseDuration('2h30m'))).toBe('2h30m');
    expect(formatDuration(parseDuration('1h15m30s'))).toBe('1h15m30s');
    expect(formatDuration(parseDuration('5m'))).toBe('5m');
  });
});
```

## Acceptance Criteria

- `DurationSchema` accepts valid duration strings like `"5m"`, `"1h"`, `"30s"`, `"2h30m"`, `"1h15m30s"`.
- `DurationSchema` rejects empty strings and non-duration strings.
- `parseDuration("2h30m")` returns `9_000_000` (milliseconds).
- `formatDuration(9_000_000)` returns `"2h30m"`.
- `formatDuration(0)` returns `"0s"`.
- Round-trip `formatDuration(parseDuration(x)) === x` holds for valid duration strings.
- All duration tests pass.

Implement the task and command extension schemas that build on top of `SkillFrontmatterSchema`, plus comprehensive tests for both.

## Implementation: `packages/skills/src/task-schema.ts`

```typescript
import { z } from 'zod';
import { SkillFrontmatterSchema } from './schema.js';
import { DurationSchema } from './duration.js';

/**
 * Task frontmatter schema — a superset of the SKILL.md base.
 *
 * Adds scheduling, execution constraints, and display customization.
 * Fields that depend on installation context (agentId, cwd) are
 * intentionally excluded — they are derived from the file's location
 * on disk and stored in the DB only.
 */
export const TaskFrontmatterSchema = SkillFrontmatterSchema.extend({
  /** Human-readable display name. Falls back to humanized `name` if absent. */
  'display-name': z.string().optional(),

  /** Cron expression for scheduling. Absent means on-demand only. */
  cron: z.string().optional(),

  /** IANA timezone for cron evaluation. */
  timezone: z.string().default('UTC'),

  /** Whether the task is active. Disabled tasks are not scheduled. */
  enabled: z.boolean().default(true),

  /** Maximum execution time. Duration string: "5m", "1h", "30s", "2h30m". */
  'max-runtime': DurationSchema.optional(),

  /**
   * Agent permission mode during task execution.
   * - `acceptEdits`: agent can edit files with approval
   * - `bypassPermissions`: agent runs without approval gates
   */
  permissions: z.enum(['acceptEdits', 'bypassPermissions']).default('acceptEdits'),
});

export type TaskFrontmatter = z.infer<typeof TaskFrontmatterSchema>;
```

## Implementation: `packages/skills/src/command-schema.ts`

```typescript
import { z } from 'zod';
import { SkillFrontmatterSchema } from './schema.js';

/**
 * Command frontmatter schema — a superset of the SKILL.md base.
 *
 * Aligns with Claude Code's slash command extensions on top of the
 * agentskills.io base spec.
 */
export const CommandFrontmatterSchema = SkillFrontmatterSchema.extend({
  /** Parameter hint shown in autocomplete (e.g., "[issue-number]"). */
  'argument-hint': z.string().optional(),

  /** Prevent automatic loading by the model. Use for explicit-only commands. */
  'disable-model-invocation': z.boolean().optional(),

  /** Whether this command appears in the `/` menu. Default: true. */
  'user-invocable': z.boolean().default(true),

  /** Execution context. "fork" runs in an isolated subagent. */
  context: z.enum(['fork']).optional(),

  /** Subagent type when context is "fork". */
  agent: z.string().optional(),

  /** Model override for this command's execution. */
  model: z.string().optional(),

  /** Effort level override. */
  effort: z.enum(['low', 'medium', 'high', 'max']).optional(),
});

export type CommandFrontmatter = z.infer<typeof CommandFrontmatterSchema>;
```

